,p_display_point=>'REGION_POSITION_02'
,p_source_type=>'NATIVE_SQL_REPORT'
,p_query_type=>'SQL'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'select "USER_ID",',
'    null LINK_CLASS,',
'    apex_page.get_url(p_items => ''P2_USER_ID'', p_values => "USER_ID") LINK,',
'    null ICON_CLASS,',
'    null LINK_ATTR,',
'    null ICON_COLOR_CLASS,',
'    case when coalesce(:P2_USER_ID,''0'') = "USER_ID"',
'      then ''is-active'' ',
'      else '' ''',
'    end LIST_CLASS,',
'    (substr("DISPLAY_NAME", 1, 50)||( case when length("DISPLAY_NAME") > 50 then ''...'' else '''' end )) LIST_TITLE,',
'    (substr("USERNAME", 1, 50)||( case when length("USERNAME") > 50 then ''...'' else '''' end )) LIST_TEXT,',
'    null LIST_BADGE',
'from "USERS" x',
'where (:P2_SEARCH is null',
'        or upper(x."DISPLAY_NAME") like ''%''||upper(:P2_SEARCH)||''%''',
'        or upper(x."USERNAME") like ''%''||upper(:P2_SEARCH)||''%''',
'    )',
'order by "DISPLAY_NAME"'))
,p_ajax_enabled=>'Y'
,p_ajax_items_to_submit=>'P2_SEARCH'
